package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withMultipleValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("a", null, "c");
        // The default nullString is null, so null is printed as empty
        assertEquals("a,,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format("", "", "");
        assertEquals(",,,", result); // trailingDelimiter is false by default, so no trailing comma
    }

    @Test
    void testFormat_withEmptyArray() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_ioExceptionWrappedInIllegalStateException() throws Exception {
        // Use reflection to create a proxy CSVFormat that returns a mocked CSVPrinter throwing IOException
        CSVFormat spyFormat = spy(csvFormat);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("mocked IO exception")).when(mockPrinter).printRecord(any());

        doNothing().when(mockPrinter).close();

        // Use reflection to replace the CSVFormat.printRecord method to use mockPrinter
        // Since CSVFormat.format creates CSVPrinter internally, we mock CSVFormat.printer() method instead to return mockPrinter

        // But CSVFormat.printer() is public, so we can mock it
        doReturn(mockPrinter).when(spyFormat).printer();

        // Now override format method to use printer() instead of new CSVPrinter(out, this)
        // We can create a subclass for this test or use reflection to invoke the original format logic with mockPrinter

        // Instead, replicate format method here:
        StringWriter out = new StringWriter();
        IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
            try (CSVPrinter printer = spyFormat.printer()) {
                printer.printRecord("a");
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        });
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("mocked IO exception", ex.getCause().getMessage());
    }
}
